#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

#define DICT_PATH "/usr/share/dict/words"
#define BUFFER_SIZE 256

int main(int argc, char *argv[]) {
 FILE *dict;
 char buffer[BUFFER_SIZE];
 char *word;
 int found = 0;

 // Check command-line arguments
 if (argc != 2) {
 fprintf(stderr, "Usage: %s <word>\n", argv[0]);
 return EXIT_FAILURE;
 }

 // Convert input word to lowercase for comparison
 word = argv[1];
 for (int i = 0; word[i]; i++) {
 word[i] = tolower(word[i]);
 }

 // Open dictionary file
 dict = fopen(DICT_PATH, "r");
 if (dict == NULL) {
 perror("Error opening dictionary");
 return EXIT_FAILURE;
 }

 // Search for word in dictionary
 while (fgets(buffer, BUFFER_SIZE, dict) != NULL) {
 // Remove trailing newline
 buffer[strcspn(buffer, "\n")] = '\0';

 // Convert dictionary word to lowercase
 for (int i = 0; buffer[i]; i++) {
 buffer[i] = tolower(buffer[i]);
 }

 // Compare words
 if (strcmp(buffer, word) == 0) {
 found = 1;
 break;
 }
 }

 // Report result
 if (found) {
 printf("'%s' found in dictionary.\n", argv[1]);
 } else {
 printf("'%s' NOT found in dictionary.\n", argv[1]);
 }

 fclose(dict);
 return EXIT_SUCCESS;
}

#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <ctype.h>

#define DICT_PATH "/usr/share/dict/words"
#define TABLE_SIZE 100000

// Simple hash table structure
typedef struct HashNode {
 char *word;
 struct HashNode *next;
} HashNode;

HashNode *hashTable[TABLE_SIZE];

// DJB2 hash function
unsigned int hash(const char *str) {
 unsigned int hash = 5381;
 int c;
 while ((c = *str++)) {
 hash = ((hash << 5) + hash) + c;
 }
 return hash % TABLE_SIZE;
}

// Insert word into hash table
void insert(const char *word) {
 unsigned int index = hash(word);
 HashNode *newNode = malloc(sizeof(HashNode));
 newNode->word = strdup(word);
 newNode->next = hashTable[index];
 hashTable[index] = newNode;
}

// Search for word in hash table
int search(const char *word) {
 unsigned int index = hash(word);
 HashNode *node = hashTable[index];
 while (node) {
 if (strcmp(node->word, word) == 0) return 1;
 node = node->next;
 }
 return 0;
}

// Load dictionary into hash table
int loadDictionary(const char *path) {
 FILE *dict = fopen(path, "r");
 if (!dict) return -1;

 char buffer[256];
 while (fgets(buffer, sizeof(buffer), dict)) {
 buffer[strcspn(buffer, "\n")] = '\0';
 // Convert to lowercase for case-insensitive search
 for (int i = 0; buffer[i]; i++) buffer[i] = tolower(buffer[i]);
 if (strlen(buffer) > 0) insert(buffer);
 }

 fclose(dict);
 return 0;
}

int main(int argc, char *argv[]) {
 if (argc != 2) {
 fprintf(stderr, "Usage: %s <word>\n", argv[0]);
 return 1;
 }

 // Initialize hash table
 for (int i = 0; i < TABLE_SIZE; i++) hashTable[i] = NULL;

 // Load dictionary
 if (loadDictionary(DICT_PATH) == -1) {
 perror("Failed to load dictionary");
 return 1;
 }

 // Convert search word to lowercase
 char *word = argv[1];
 for (int i = 0; word[i]; i++) word[i] = tolower(word[i]);

 // Search and report
 if (search(word)) {
 printf("'%s' found in dictionary.\n", word);
 } else {
 printf("'%s' NOT found in dictionary.\n", word);
 }

 return 0;
}
